#include "FixedWing.h"

#include <math.h>
#include <string.h>

static inline void set_y(FixedWing_t *m, int index, real_t value) {
    if (index >= 0 && index < FIXEDWING_Y_LEN) {
        m->y[index] = value;
    }
}

static inline void set_p(FixedWing_t *m, int index, real_t value) {
    if (index >= 0 && index < FIXEDWING_P_LEN) {
        m->p[index] = value;
    }
}

static inline int event_crossed(real_t previous, real_t current) {
    return (previous < 0.0 && current >= 0.0) || (previous > 0.0 && current <= 0.0);
}

static inline real_t relation_memory_value(real_t previous, real_t current) {
    if (current < 0.0) {
        return 1.0;
    }
    if (current > 0.0) {
        return 0.0;
    }
    if (previous > 0.0) {
        return 1.0;
    }
    return 0.0;
}

#define RUMOCA_MAX_LINEAR_SOLVE 8
static inline real_t __rumoca_solve_linear_component(
    const real_t *A_in,
    const real_t *b_in,
    int n,
    int component
) {
    if (n <= 0 || n > RUMOCA_MAX_LINEAR_SOLVE || component < 0 || component >= n) {
        return NAN;
    }

    real_t A[RUMOCA_MAX_LINEAR_SOLVE][RUMOCA_MAX_LINEAR_SOLVE] = {0};
    real_t b[RUMOCA_MAX_LINEAR_SOLVE] = {0};
    for (int row = 0; row < n; row++) {
        b[row] = b_in[row];
        for (int col = 0; col < n; col++) {
            A[row][col] = A_in[row * n + col];
        }
    }

    for (int col = 0; col < n; col++) {
        int pivot = col;
        real_t pivot_abs = fabs(A[col][col]);
        for (int row = col + 1; row < n; row++) {
            real_t candidate = fabs(A[row][col]);
            if (candidate > pivot_abs) {
                pivot = row;
                pivot_abs = candidate;
            }
        }
        if (pivot_abs < 1.0e-12) {
            return NAN;
        }
        if (pivot != col) {
            for (int j = col; j < n; j++) {
                real_t tmp = A[col][j];
                A[col][j] = A[pivot][j];
                A[pivot][j] = tmp;
            }
            real_t tmp_b = b[col];
            b[col] = b[pivot];
            b[pivot] = tmp_b;
        }

        real_t inv_pivot = 1.0 / A[col][col];
        for (int row = col + 1; row < n; row++) {
            real_t factor = A[row][col] * inv_pivot;
            A[row][col] = 0.0;
            for (int j = col + 1; j < n; j++) {
                A[row][j] -= factor * A[col][j];
            }
            b[row] -= factor * b[col];
        }
    }

    real_t x[RUMOCA_MAX_LINEAR_SOLVE] = {0};
    for (int row = n - 1; row >= 0; row--) {
        real_t sum = b[row];
        for (int col = row + 1; col < n; col++) {
            sum -= A[row][col] * x[col];
        }
        x[row] = sum / A[row][row];
    }
    return x[component];
}

